import java.util.*;
import java.io.*;


class Solution{
    public static void main(String[] args){
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();

        for(int i = 1; i<=N;i++){
            char ch = (char)(65+(i-1));
            StringBuilder sb = new StringBuilder();
            for(int j = 0; j < i; j++){
                sb.append(ch);
            }
            for(int j = 0; j < N-i; j++){
                sb.append("  ");
            }
            for(int j = 0; j < i; j++){
                sb.append(ch);
            }
            System.out.println(sb.toString());
        }
    }
}
